B.aA1=new A.co("",null,null,null,null,"Acquired Demyelinating Neuropathy (CIDP)",B.as,"Uniform slowing WITH conduction block/temporal dispersion suggests CIDP. However, this combination is unusual -- acquired demyelination is typically non-uniform. Re-examine for segmental features. CIDP responds to IVIG, plasmapheresis, or immunosuppression.")
B.azL=new A.co("",null,null,null,null,"Hereditary Demyelinating Neuropathy (CMT1)",B.b4,"Uniform slowing WITHOUT conduction block or temporal dispersion is the hallmark of inherited demyelinating neuropathy (CMT1). Median motor CV typically <38 m/s. Check PMP-22 duplication (chromosome 17p11.2). Family history is key.")
B.azM=new A.co("Is there conduction block or temporal dispersion?","CB/TD present","No CB or TD",B.aA1,B.azL,null,null,null)
B.aA7=new A.co("",null,null,null,null,"Multifocal Motor Neuropathy with CB (MMNCB)",B.af,"Motor conduction block with NORMAL sensory conduction across the same segment is the hallmark of MMNCB. This is a treatable mimic of ALS. Check anti-GM1 antibodies. Responds to IVIG. Does NOT respond to steroids or plasma exchange.")
B.azO=new A.co("",null,null,null,null,"Acquired Demyelinating Neuropathy (GBS/CIDP)",B.as,"Segmental demyelination with conduction block and sensory involvement suggests acquired inflammatory demyelinating polyneuropathy. If acute (<4 weeks) = GBS/AIDP; if chronic (>8 weeks) = CIDP. Both are treatable.")
B.azR=new A.co("Are sensory NCS normal across the same nerve segments?","Sensory normal","Sensory also abnormal",B.aA7,B.azO,null,null,null)
B.aA3=new A.co("",null,null,null,null,"Acquired Demyelinating Neuropathy",B.as,"Non-uniform slowing without overt conduction block can still be acquired demyelination. Check for prolonged distal latencies (>130% ULN) and prolonged F-waves (>130% ULN). Apply CIDP diagnostic criteria (2021 EAN/PNS).")
B.aAa=new A.co("Is there conduction block at non-entrapment sites?","Conduction block present","No conduction block",B.azR,B.aA3,null,null,null)
B.aAf=new A.co("Is the slowing UNIFORM across all nerves, or SEGMENTAL/MULTIFOCAL?","Uniform (all nerves similar)","Segmental/multifocal",B.azM,B.aAa,null,null,null)
B.aA0=new A.co("",null,null,null,null,"Axonal Polyneuropathy",B.ae,"Reduced amplitudes with near-normal velocities and a length-dependent gradient = axonal polyneuropathy. The most common pattern. Evaluate for diabetes, alcohol, B12, medications, and toxic exposures. EMG shows fibrillations and neurogenic MUAPs in distal muscles.")
B.azH=new A.co("",null,null,null,null,"Mononeuropathy Multiplex or Non-Length-Dependent Process",B.b3,"Asymmetric or non-length-dependent amplitude loss suggests mononeuropathy multiplex (vasculitis, diabetes, sarcoidosis) or a non-length-dependent process (ganglionopathy, motor neuron disease). Pattern distribution is the key differentiator.")
B.azP=new A.co("Is the pattern length-dependent (legs worse than arms, distal worse than proximal)?","Length-dependent","Non-length-dependent",B.aA0,B.azH,null,null,null)
B.azK=new A.co("",null,null,null,null,"Normal or Subclinical -- Correlate Clinically",B.aj,"Near-normal velocities and amplitudes may still be abnormal if compared to the contralateral side or normative data. Consider: (1) very early neuropathy not yet detectable, (2) pure small fiber neuropathy (normal NCS by definition), (3) technical factors. Clinical correlation is essential.")
B.aAc=new A.co("Are CMAP and/or SNAP AMPLITUDES significantly reduced?","Amplitudes reduced","Amplitudes normal",B.azP,B.azK,null,null,null)
B.azI=new A.co("NCS shows abnormalities. Is there significant CONDUCTION VELOCITY slowing (motor CV <75% LLN)?","Significant CV slowing","CV near normal or mildly slow",B.aAf,B.aAc,null,null,null)
B.Te=new A.t6("Axonal vs Demyelinating","Classify the NCS pattern systematically.",B.azI,B.ec,null)
B.azQ=new A.co("",null,null,null,null,"L5 Radiculopathy",B.ae,"Tibialis posterior (inversion) + gluteals + paraspinals all share L5 innervation but different peripheral nerves. Abnormal paraspinals confirm the lesion is at or proximal to the root. SNAP should be normal (preganglionic).")
B.aA6=new A.co("",null,null,null,null,"Lumbosacral Plexopathy",B.b3,"Multiple nerve territories involved beyond the peroneal nerve, but paraspinals are spared. SNAP will be ABNORMAL (postganglionic lesion). Check for diabetic amyotrophy, retroperitoneal hematoma, or mass lesion.")
B.azD=new A.co("Are paraspinal muscles abnormal on EMG?","Paraspinals abnormal","Paraspinals normal",B.azQ,B.aA6,null,null,null)
B.aA2=new A.co("",null,null,null,null,"Sciatic Neuropathy (peroneal division)",B.af,"Short head of biceps femoris is the ONLY peroneal-division muscle above the fibular head. If abnormal, the lesion must be proximal to the knee -- within the sciatic nerve or higher. Sural SNAP will be abnormal.")
B.aAd=new A.co("",null,null,null,null,"L5 Radiculopathy (without paraspinal findings)",B.ae,"Tibialis posterior involvement points to L5, but short head BF (also peroneal/L5) is normal. This pattern can occur in incomplete L5 radiculopathy. Consider that paraspinals may be normal in up to 50% of radiculopathies.")
B.aAb=new A.co("Is the short head of biceps femoris abnormal on EMG?","Short head BF abnormal","Short head BF normal",B.aA2,B.aAd,null,null,null)
B.azT=new A.co("Are hip abductors (gluteus medius) or extensors weak?","Hip muscles weak","Hip muscles normal",B.azD,B.aAb,null,null,null)
B.azN=new A.co("",null,null,null,null,"Common Peroneal (Fibular) Neuropathy at Fibular Head",B.as,"Ankle inversion is PRESERVED (tibialis posterior is tibial nerve, not peroneal). Focal conduction block or slowing across the fibular head confirms the most common site of peroneal nerve compression. Excellent prognosis if demyelinating.")
B.aA8=new A.co("",null,null,null,null,"Peroneal Neuropathy (axonal, at fibular head)",B.as,"Axonal peroneal neuropathy may not show focal conduction changes across the fibular head, but the abnormal superficial peroneal SNAP confirms a peripheral nerve lesion distal to the DRG. Recovery depends on degree of axonal loss.")
B.azU=new A.co("",null,null,null,null,"Consider L5 Radiculopathy",B.ae,"Normal superficial peroneal SNAP with foot drop and no focal peroneal changes raises suspicion for L5 radiculopathy (SNAP normal because lesion is preganglionic). Check tibialis posterior and paraspinals carefully.")
B.aA9=new A.co("Is the superficial peroneal SNAP abnormal?","Superficial peroneal SNAP abnormal","Superficial peroneal SNAP normal",B.aA8,B.azU,null,null,null)
B.azB=new A.co("Is there conduction block or slowing across the fibular head on NCS?","Focal slowing at fibular head","No focal change",B.azN,B.aA9,null,null,null)
B.aA5=new A.co("Patient presents with foot drop. Is ankle INVERSION weak?","Inversion weak","Inversion intact",B.azT,B.azB,null,null,null)
B.Tf=new A.t6("Foot Drop Localization","Work through the clinical reasoning step by step.",B.aA5,B.dI,null)
B.azV=new A.co("",null,null,null,null,"Motor Neuron Disease (ALS)",B.ae,"Combined UMN + LMN signs in multiple body regions is the hallmark of ALS. EDX shows widespread denervation with reinnervation, normal sensory studies, and fasciculations. Must meet Gold Coast or Awaji criteria. Rule out cervical myelopathy + polyneuropathy as mimics.")
B.aA_=new A.co("",null,null,null,null,"Central Lesion (brain/spinal cord)",B.Y,"Pure UMN pattern points to a central process. EMG is NOT typically indicated -- order brain/spine MRI instead. Consider stroke, MS, myelopathy, PLS. EMG may be useful to exclude coexisting peripheral pathology.")
B.azZ=new A.co("Are there also LOWER motor neuron signs (atrophy, fasciculations, hyporeflexia)?","Mixed UMN + LMN","Pure UMN",B.azV,B.aA_,null,null,null)
B.aA4=new A.co("",null,null,null,null,"Polyradiculopathy or Plexopathy",B.b3,"Proximal weakness + sensory involvement suggests root or plexus level pathology. CIDP can also present this way. Check SNAPs (normal = radiculopathy; abnormal = plexus or CIDP) and paraspinals.")
B.aAe=new A.co("",null,null,null,null,"Neuromuscular Junction Disorder",B.af,"Fatigable proximal weakness without sensory involvement suggests MG or LEMS. Order repetitive nerve stimulation (3 Hz, look for >10% decrement). Check AChR and MuSK antibodies. LEMS: check baseline CMAP amplitudes (low = presynaptic).")
B.azS=new A.co("",null,null,null,null,"Myopathy",B.aK,"Proximal weakness + elevated CK + pure motor = myopathy. EMG shows short-duration, low-amplitude, polyphasic MUAPs with early recruitment. Consider inflammatory (PM/DM), dystrophic (LGMD), or metabolic causes. Biopsy may be needed.")
B.azC=new A.co("",null,null,null,null,"Myopathy (possible) or Motor Neuron Disease",B.aK,"Normal CK does not exclude myopathy (e.g., steroid myopathy, endocrine). Also consider SMA or slowly progressive MND. EMG pattern will differentiate: myopathic (short/small MUAPs, early recruitment) vs neurogenic (long/large MUAPs, reduced recruitment).")
B.azW=new A.co("Is CK elevated?","CK elevated","CK normal",B.azS,B.azC,null,null,null)
B.azJ=new A.co("Does weakness fluctuate with fatigue or time of day?","Fluctuating","Progressive/stable",B.aAe,B.azW,null,null,null)
B.azY=new A.co("Are sensory symptoms present?","Sensory symptoms","Pure motor",B.aA4,B.azJ,null,null,null)
B.azE=new A.co("",null,null,null,null,"Peripheral Polyneuropathy",B.ec,"Distal weakness + abnormal sensory studies = peripheral polyneuropathy. Classify as axonal vs demyelinating based on NCS pattern. Length-dependent (stocking-glove) is most common. Consider diabetes, alcohol, B12 deficiency, medications.")
B.azX=new A.co("",null,null,null,null,"Distal Motor Neuropathy or MND",B.ae,"Distal weakness with NORMAL sensory studies is concerning for motor neuron disease (especially if fasciculations present). Also consider multifocal motor neuropathy with conduction block (MMNCB) -- check for motor conduction block with normal sensory across the same segments. Anti-GM1 antibodies support MMNCB.")
B.azF=new A.co("Are sensory NCS abnormal?","SNAPs abnormal","SNAPs normal",B.azE,B.azX,null,null,null)
B.azG=new A.co("Is the weakness PROXIMAL (shoulders, hips) or DISTAL (hands, feet)?","Proximal","Distal",B.azY,B.azF,null,null,null)
B.aAg=new A.co("Patient presents with weakness. Are there UPPER motor neuron signs (hyperreflexia, Babinski, spasticity)?","UMN signs present","No UMN signs",B.azZ,B.azG,null,null,null)
B.Tg=new A.t6("Weakness Differential","Localize the lesion: UMN, LMN, NMJ, or muscle?",B.aAg,B.b3,null)
