B.aar=new A.Gd("Brachial Plexus Masterclass","Mastering Geographic Neuro-Localization",B.bn,null)
B.fb=new A.UP(0,"latestPointer")
B.oT=new A.UP(1,"averageBoundaryPointers")
B.aas=new A.Gj(null)
B.B8=new A.ug(0,"clipRect")
