c8=A.ci("Baxter's Neuropathy",d0,s2,"INDICATED (To differentiate from common heel pain causes)",A.a([A.u(!0,f0,f0,j8,f0,f0,"Abductor Digiti Quinti (ADQ)","Lateral Plantar (Baxter's)",f0,h4,m6,f0),A.u(!1,"Spared (confirms focal localization)",f0,f0,f0,f0,"Abductor Hallucis (AH)","Medial Plantar",f0,f0,m6,f0),A.u(!1,h7,f0,f0,f0,f0,m4,m5,f0,f0,m6,f0),A.u(!1,h7,f0,f0,f0,f0,l5,l6,f0,f0,q3,f0),A.u(!1,h7,f0,f0,f0,f0,m0,l6,f0,f0,q5,f0),A.u(!1,h7,f0,f0,f0,f0,m2,q6,f0,f0,m1,f0),A.u(!1,h7,f0,f0,f0,f0,m7,m8,f0,f0,m9,f0),A.u(!1,f0,f0,f0,f0,f0,ae4,f0,f0,f0,f0,k6)],n),"Entrapment of the Inferior Calcaneal Nerve (first branch of the lateral plantar nerve) between the abductor hallucis and quadratus plantae. The hallmark is isolated denervation of the Abductor Digiti Quinti (ADQ) with sparing of the Abductor Hallucis (AH) and all other proximal muscles.",c9,"baxters",d1,ae8,ae7,!0,c8,A.a(["Baxter's Nerve is the first branch of the lateral plantar nerve; it provides motor innervation to the ADQ.","Compression occurs within the deep fascia between the abductor hallucis and quadratus plantae muscles.","Localization Pearl: Isolated ADQ involvement with a Normal AH motor study and Normal Sural SNAP.","This is a common, often overlooked cause of chronic heel pain in athletes."],af3),"Chronic Heel Pain and Medial Foot Aching")
ae7=A.ch(24,"Weakness and numbness in the right hand following a fall where he caught himself by a tree branch",i1,"24-year-old male who fell from a height and reflexively grabbed a tree branch with his right hand, causing a sudden upward traction on his arm. Immediately felt sharp pain in the axilla and numbness in the medial arm and hand. Now presents 4 weeks later with progressive 'clawing' of the hand and inability to perform fine motor tasks.",i4,"Bike Messenger",i4)
ae8=A.cm("Atrophy of the thenar and hypothenar eminences. 'Claw hand' posture (hyperextension at MCP, flexion at IP joints of digits 4-5).","Tenderness in the right axilla and supraclavicular space.","2+ and symmetric throughout. No Horner's syndrome (suggests post-ganglionic trunk rather than t1 root avulsion).","Full ROM at shoulder and elbow. Limited finger extension and abduction.","Decreased light touch and pinprick on the medial aspect of the arm, forearm, and the ulnar side of the hand (digits 4-5).","Negative Spurling's test. Negative Tinel's at the wrist and elbow.","Right hand intrinsics: APB 2/5, FDI 2/5, ADM 2/5. Finger flexors (FPL/FDP) 3/5. Wrist flexors (FCU) 4/5. Triceps 5/5. Deltoid 5/5.")
d1=A.a([A.Y("Lower Trunk Brachial Plexopathy (Klumpke's)",d9),A.Y(w6,"Radiculopathy (pre-ganglionic) would spare the Medial Antebrachial Cutaneous (MAC) and Ulnar SNAPs; here both are abnormal."),A.Y("Combined Ulnar and Median Neuropathy","Would not explain the sensory loss in the medial arm/forearm (MAC territory) or the weakness in non-median/non-ulnar C8 muscles like the EIP."),A.Y(ad8,"TOS usually presents with more chronic, positional symptoms and often involves vascular changes; the acute traction injury history is highly suggestive of plexopathy."),A.Y("T1 Root Avulsion","Typically presents with Horner's syndrome (ptosis/miosis) due to disruption of sympathetic fibers; its absence here points to the trunk.")],ae9)
c9=A.aa(["constitutional",u6,"musculoskeletal","Axillary and medial arm pain. No neck pain.","neurological","Severe hand weakness and numbness in the 'medial' distribution. No leg symptoms."],af1,af1)
d0=A.a(["None indicated"],af3)
d0=A.ck(A.a(["MRI Brachial Plexus: Signal abnormality and edema in the lower trunk; no evidence of root avulsion or pseudomeningocele."],af3),d0)
